// truncateClientID truncates a client ID for display.
func truncateClientID(clientID string) string {
	if len(clientID) <= 12 {
		return clientID
	}
	return clientID[:8] + "..." + clientID[len(clientID)-4:]
}

func o2CopyToClipboard(text string) templ.ComponentScript {
	return templ.ComponentScript{
		Name: `__templ_o2CopyToClipboard_079b`,
		Function: `function __templ_o2CopyToClipboard_079b(text){navigator.clipboard.writeText(text).then(function() {
		var btn = document.activeElement;
		if (btn) {
			var originalTitle = btn.title;
			btn.title = "Copied!";
			setTimeout(function() { btn.title = originalTitle; }, 2000);
		}
	});
}`,
		Call:       templ.SafeScript(`__templ_o2CopyToClipboard_079b`, text),
		CallInline: templ.SafeScriptInline(`__templ_o2CopyToClipboard_079b`, text),
	}
}

